SELECT 
FROM attendance a
LEFT JOIN student s ON a.student_id = s.id
LEFT JOIN class_entity c ON a.class_id = c.id
LEFT JOIN sys_user u ON a.check_in_user_id = u.id
WHERE a.is_deleted = 0

    AND a.class_id = #{classId}


    AND a.student_id = #{studentId}


    AND a.attendance_date >= #{startDate}


    AND a.attendance_date <= #{endDate}

ORDER BY a.attendance_date DESC, a.student_id ASC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM attendance a
WHERE a.is_deleted = 0

    AND a.class_id = #{classId}


    AND a.student_id = #{studentId}


    AND a.attendance_date >= #{startDate}


    AND a.attendance_date <= #{endDate}

SELECT id, student_id, attendance_date, status
FROM attendance
WHERE attendance_date = #{attendanceDate}
AND student_id = #{studentId}
AND is_deleted = 0
LIMIT 1

SELECT COUNT(*) as totalCount, SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) as presentCount, SUM(CASE WHEN status = 0 THEN 1 ELSE 0 END) as absentCount, SUM(CASE WHEN status = 2 THEN 1 ELSE 0 END) as lateCount, SUM(CASE WHEN status = 3 THEN 1 ELSE 0 END) as earlyLeaveCount, SUM(CASE WHEN status = 4 THEN 1 ELSE 0 END) as leaveCount, CASE WHEN COUNT(*) > 0 THEN ROUND(SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) ELSE 0 END as attendanceRate FROM attendance WHERE class_id = #{classId} AND is_deleted = 0
AND attendance_date >= #{startDate}
AND attendance_date <= #{endDate}

SELECT COUNT(*) as totalCount, SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) as presentCount, SUM(CASE WHEN status = 0 THEN 1 ELSE 0 END) as absentCount, SUM(CASE WHEN status = 2 THEN 1 ELSE 0 END) as lateCount, SUM(CASE WHEN status = 3 THEN 1 ELSE 0 END) as earlyLeaveCount, SUM(CASE WHEN status = 4 THEN 1 ELSE 0 END) as leaveCount, CASE WHEN COUNT(*) > 0 THEN ROUND(SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) ELSE 0 END as attendanceRate FROM attendance WHERE student_id = #{studentId} AND is_deleted = 0
AND attendance_date >= #{startDate}
AND attendance_date <= #{endDate}
